function ImageGallery() {
  const [images, setImages] = React.useState([
    {url:'REPLACE_WITH_IMG_1',caption:'REPLACE_WITH_CAPTION_1'},
    {url:'https://picsum.photos/400/300?random=2',caption:'Sample 2'},
    {url:'https://picsum.photos/400/300?random=3',caption:'Sample 3'},
    {url:'https://picsum.photos/400/300?random=4',caption:'Sample 4'}
  ]);
  const [lightbox, setLightbox] = React.useState(null);

  const add = ()=>{
    const url = prompt('Image URL:');
    if(url) setImages([...images,{url,caption:''}]);
  };

  return (
    <div style={{padding:12,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:10}}>
        <span style={{fontSize:18,fontWeight:700}}>Image Gallery</span>
        <button onClick={add}
          style={{padding:'6px 12px',borderRadius:8,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer',fontSize:13}}>
          + Add
        </button>
      </div>
      <div style={{flex:1,overflow:'auto',display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:8}}>
        {images.map((img,i)=> (
          <div key={i} onClick={()=>setLightbox(i)}
            style={{cursor:'pointer',borderRadius:8,overflow:'hidden',position:'relative',aspectRatio:'4/3'}}>
            <img src={img.url} style={{width:'100%',height:'100%',objectFit:'cover'}} alt={img.caption}/>
            {img.caption && <div style={{position:'absolute',bottom:0,left:0,right:0,padding:'4px 8px',background:'rgba(0,0,0,0.5)',color:'#fff',fontSize:11}}>{img.caption}</div>}
          </div>
        ))}
      </div>
      {lightbox !== null && (
        <div onClick={()=>setLightbox(null)}
          style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.9)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:1000}}>
          <img src={images[lightbox].url} style={{maxWidth:'90%',maxHeight:'90%',borderRadius:8}} alt=""/>
        </div>
      )}
    </div>
  );
}
render(<ImageGallery/>);
